        // initialize network info
        NetworkInfos.setDefault(nisConfiguration.getNetworkInfo());
        // initialize other globals
        final NamespaceCacheLookupAdapters adapters = new NamespaceCacheLookupAdapters(this.namespaceCache());
        if (nisConfiguration.ignoreFees()) {
            NemGlobals.setTransactionFeeCalculator(new ZeroTransactionFeeCalculator());
        } else {
            NemGlobals.setTransactionFeeCalculator(new DefaultTransactionFeeCalculator(adapters.asMosaicFeeInformationLookup(), () -> this.blockChainLastBlockLayer.getLastBlockHeight().next(), new BlockHeight[] { nisConfiguration.getForkConfiguration().getFeeFork().getFirstHeight(), nisConfiguration.getForkConfiguration().getFeeFork().getSecondHeight() }));
